using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Student_EnrollmentDate_CanBeSet()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Student_Enrollments_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment>
                {
                    new Enrollment { EnrollmentID = 1, CourseID = 100 },
                    new Enrollment { EnrollmentID = 2, CourseID = 200 }
                }
            };
            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Student_Enrollments_DefaultsToNull()
        {
            var student = new Student();
            Assert.Null(student.Enrollments);
        }

        [Fact]
        public void Student_RequiredFields_Validation()
        {
            var student = new Student { EnrollmentDate = DateTime.Today };
            var context = new ValidationContext(student);
            var results = new List<ValidationResult>();

            var isValid = Validator.TryValidateProperty(student.LastName,
                new ValidationContext(student) { MemberName = "LastName" }, results);

            Assert.False(isValid);
        }

        [Fact]
        public void Student_ValidModel_PassesValidation()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var context = new ValidationContext(student);
            var results = new List<ValidationResult>();

            var isValid = Validator.TryValidateObject(student, context, results, true);

            Assert.True(isValid);
            Assert.Empty(results);
        }

        [Fact]
        public void Student_LastName_TooLong_FailsValidation()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = new string('A', 51),
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(student);

            Validator.TryValidateObject(student, context, results, true);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_TooLong_FailsValidation()
        {
            var student = new Student
            {
                FirstMidName = new string('A', 51),
                LastName = "Doe",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(student);

            Validator.TryValidateObject(student, context, results, true);

            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }
    }
}

