using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class DepartmentTests
    {
        [Fact]
        public void Department_Properties_CanBeSet()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 500000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 5,
                RowVersion = new byte[] { 1, 2, 3, 4 }
            };
            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(500000, dept.Budget);
            Assert.Equal(new DateTime(2020, 1, 1), dept.StartDate);
            Assert.Equal(5, dept.InstructorID);
            Assert.Equal(new byte[] { 1, 2, 3, 4 }, dept.RowVersion);
        }

        [Fact]
        public void Department_InstructorID_Nullable()
        {
            var dept = new Department { Name = "Test", InstructorID = null };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_Name_TooShort_FailsValidation()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Today
            };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(dept);

            Validator.TryValidateObject(dept, context, results, true);

            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Name_TooLong_FailsValidation()
        {
            var dept = new Department
            {
                Name = new string('X', 51),
                Budget = 100000,
                StartDate = DateTime.Today
            };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(dept);

            Validator.TryValidateObject(dept, context, results, true);

            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_ValidModel_PassesValidation()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 100000,
                StartDate = DateTime.Today
            };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(dept);

            var isValid = Validator.TryValidateObject(dept, context, results, true);

            Assert.True(isValid);
        }
    }
}

