using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_Properties_CanBeSet()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 200,
                Grade = Grade.A
            };
            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(100, enrollment.CourseID);
            Assert.Equal(200, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_IsNullable()
        {
            var enrollment = new Enrollment { Grade = null };
            Assert.Null(enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Enrollment_Grade_AllValues(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_NavigationProperties_DefaultToNull()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Course);
            Assert.Null(enrollment.Student);
        }
    }
}

