using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestHelper.CreateInMemoryContext();

            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = System.DateTime.Today
            });
            context.SaveChanges();

            var student = context.Students.First();
            Assert.Equal("Test", student.FirstMidName);
            Assert.Equal("User", student.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            using var context = TestHelper.CreateInMemoryContext();

            var dept = new Department { Name = "Test Dept", Budget = 1000, StartDate = System.DateTime.Today };
            context.Departments.Add(dept);
            context.SaveChanges();

            context.Courses.Add(new Course { CourseID = 999, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID });
            context.SaveChanges();

            var course = context.Courses.First();
            Assert.Equal("Test Course", course.Title);
            Assert.Equal(999, course.CourseID);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestHelper.CreateInMemoryContext();

            context.Instructors.Add(new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = System.DateTime.Today
            });
            context.SaveChanges();

            Assert.Single(context.Instructors);
        }

        [Fact]
        public void CourseAssignment_CompositeKey_Works()
        {
            using var context = TestHelper.CreateInMemoryContext();

            var instructor = new Instructor { FirstMidName = "Test", LastName = "Instructor", HireDate = System.DateTime.Today };
            context.Instructors.Add(instructor);
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = System.DateTime.Today };
            context.Departments.Add(dept);
            context.SaveChanges();

            context.Courses.Add(new Course { CourseID = 100, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID });
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { CourseID = 100, InstructorID = instructor.ID });
            context.SaveChanges();

            var ca = context.CourseAssignments.First();
            Assert.Equal(100, ca.CourseID);
            Assert.Equal(instructor.ID, ca.InstructorID);
        }

        [Fact]
        public void CanAddAndRetrieveEnrollment()
        {
            using var context = TestHelper.CreateInMemoryContext();

            var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = System.DateTime.Today };
            context.Students.Add(student);
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = System.DateTime.Today };
            context.Departments.Add(dept);
            context.SaveChanges();
            context.Courses.Add(new Course { CourseID = 200, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID });
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment { StudentID = student.ID, CourseID = 200, Grade = Grade.A });
            context.SaveChanges();

            var enrollment = context.Enrollments.First();
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void DbSets_AreNotNull()
        {
            using var context = TestHelper.CreateInMemoryContext();

            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.Notifications);
            Assert.NotNull(context.People);
        }
    }
}
