using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
            var notification = service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "42", EntityOperation.UPDATE);
            var notification = service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_UsesDisplayName()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "42", "Jane Smith", EntityOperation.UPDATE);
            var notification = service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("Jane Smith", notification.Message);
            Assert.DoesNotContain("ID:", notification.Message);
        }

        [Fact]
        public void SendNotification_Create_GeneratesCorrectMessage()
        {
            var service = new NotificationService();
            service.SendNotification("Course", "101", "Math", EntityOperation.CREATE, "user1");
            var n = service.ReceiveNotification();

            Assert.Contains("created", n.Message);
            Assert.Contains("Math", n.Message);
        }

        [Fact]
        public void SendNotification_Update_GeneratesCorrectMessage()
        {
            var service = new NotificationService();
            service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE, "user1");
            var n = service.ReceiveNotification();

            Assert.Contains("updated", n.Message);
        }

        [Fact]
        public void SendNotification_Delete_GeneratesCorrectMessage()
        {
            var service = new NotificationService();
            service.SendNotification("Course", "101", "Math", EntityOperation.DELETE, "user1");
            var n = service.ReceiveNotification();

            Assert.Contains("deleted", n.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);
            var n = service.ReceiveNotification();

            Assert.Equal("System", n.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Drain the static queue first
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            var result = service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_ReturnsInFIFOOrder()
        {
            // Drain static queue
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("A", "1", EntityOperation.CREATE);
            service.SendNotification("B", "2", EntityOperation.UPDATE);
            service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();
            var third = service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.MarkAsRead(999));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_MultipleMessages_AllRetrievable()
        {
            var service = new NotificationService();
            // Drain static queue
            while (service.ReceiveNotification() != null) { }

            for (int i = 0; i < 5; i++)
            {
                service.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (service.ReceiveNotification() != null) count++;

            Assert.Equal(5, count);
        }
    }
}

