using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateInMemoryContext();
            TestHelper.SeedDatabase(_context);
            _controller = new StudentsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateItemExpireCallback()));
        }

        private static TempDataDictionary CreateTempData()
        {
            var httpContext = new DefaultHttpContext();
            var tempDataProvider = new CookieTempDataProvider(Microsoft.Extensions.Options.Options.Create(new CookieTempDataProviderOptions()));
            return new TempDataDictionary(httpContext, tempDataProvider);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [Fact]
        public void Index_DefaultSort_ReturnsView()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n), names);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderByDescending(n => n), names);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d), dates);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d), dates);
        }

        [Fact]
        public void Index_SearchString_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "Alex", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NoSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            _controller.Index("Date", null, "test", null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsCorrectSortParms()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var studentId = _context.Students.First().ID;

            var result = _controller.Details(studentId) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(studentId, student.ID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidStudent_AddsToDatabase()
        {
            var initialCount = _context.Students.Count();
            var student = new Student
            {
                FirstMidName = "Added",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(initialCount + 1, _context.Students.Count());
        }

        [Fact]
        public void Create_POST_InvalidEnrollmentDate_Default_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_POST_InvalidEnrollmentDate_OutOfRange_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { EnrollmentDate = DateTime.Today };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            var studentId = _context.Students.First().ID;

            var result = _controller.Edit(studentId) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(studentId, student.ID);
        }

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            var existing = _context.Students.First();
            // Detach the tracked entity so we can update it
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var student = new Student
            {
                ID = existing.ID,
                FirstMidName = "Updated",
                LastName = "Name",
