            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructor()
        {
            // Create an instructor without department references for clean deletion
            var instructor = new Instructor
            {
                FirstMidName = "ToDelete",
                LastName = "Me",
                HireDate = DateTime.Today
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var initialCount = _context.Instructors.Count();
            var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(initialCount - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            var instructor = _context.Instructors.First();
            var dept = _context.Departments.FirstOrDefault(d => d.InstructorID == instructor.ID);

            if (dept != null)
            {
                _controller.DeleteConfirmed(instructor.ID);
                _context.Entry(dept).Reload();
                Assert.Null(dept.InstructorID);
            }
        }
    }
}

