namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);

            // Drain the static notification queue from previous tests
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccess()
        {
            var result = _controller.GetNotifications() as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue some notifications
            var service = new NotificationService();
            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
            service.SendNotification("Course", "2", "Math 101", EntityOperation.UPDATE, "admin");

            var result = _controller.GetNotifications() as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.True((int)countProp.GetValue(value) >= 2);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var service = new NotificationService();
            // Drain first
            while (service.ReceiveNotification() != null) { }

            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications() as JsonResult;
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");

            Assert.True((int)countProp.GetValue(value) <= 10);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;

            Assert.NotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }
    }
}

