namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelper.CreateInMemoryContext();
            TestHelper.SeedDatabase(_context);

            // Seed course assignments for instructors
            var instructor = _context.Instructors.First();
            var course = _context.Courses.First();
            if (!_context.CourseAssignments.Any())
            {
                _context.CourseAssignments.Add(new CourseAssignment
                {
                    InstructorID = instructor.ID,
                    CourseID = course.CourseID
                });
                _context.SaveChanges();
            }

            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [Fact]
        public void Index_NoSelection_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.True(model.Instructors.Any());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Any());
            Assert.Equal(instructor.ID, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Details_ValidId_ReturnsView()
        {
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Details(instructorId) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.Equal(instructorId, instructor.ID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_POST_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "WithCourses",
                HireDate = new DateTime(2020, 1, 15)
            };
            var courseIds = _context.Courses.Select(c => c.CourseID.ToString()).ToArray();

            _controller.Create(instructor, courseIds);

            var saved = _context.Instructors
                .Where(i => i.LastName == "WithCourses")
                .Select(i => i.CourseAssignments)
                .FirstOrDefault();
            Assert.NotNull(saved);
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor { HireDate = DateTime.Today };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsView()
        {
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Delete(instructorId) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.Equal(instructorId, instructor.ID);
        }

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructor()
        {
            // Create an instructor without department references for clean deletion
            var instructor = new Instructor
            {
                FirstMidName = "ToDelete",
                LastName = "Me",
                HireDate = DateTime.Today
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var initialCount = _context.Instructors.Count();
            var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(initialCount - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            var instructor = _context.Instructors.First();
            var dept = _context.Departments.FirstOrDefault(d => d.InstructorID == instructor.ID);

            if (dept != null)
            {
                _controller.DeleteConfirmed(instructor.ID);
                _context.Entry(dept).Reload();
                Assert.Null(dept.InstructorID);
            }
        }
    }
}
