using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelper.CreateInMemoryContext();
            TestHelper.SeedDatabase(_context);
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Department>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsView()
        {
            var deptId = _context.Departments.First().DepartmentID;

            var result = _controller.Details(deptId) as ViewResult;

            Assert.NotNull(result);
            var dept = result.Model as Department;
            Assert.NotNull(dept);
            Assert.Equal(deptId, dept.DepartmentID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_GET_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Today,
                InstructorID = _context.Instructors.First().ID
            };

            var result = _controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidDepartment_AddsToDatabase()
        {
            var initialCount = _context.Departments.Count();
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Today
            };

            _controller.Create(dept);

            Assert.Equal(initialCount + 1, _context.Departments.Count());
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
