using System;
using System.IO;
using System.Linq;
using System.Text;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly string _webRootPath;

        public CoursesControllerTests()
        {
            _context = TestHelper.CreateInMemoryContext();
            TestHelper.SeedDatabase(_context);

            _webRootPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_webRootPath);

            var envMock = new Mock<IWebHostEnvironment>();
            envMock.Setup(e => e.WebRootPath).Returns(_webRootPath);
            envMock.Setup(e => e.ContentRootPath).Returns(_webRootPath);

            var loggerMock = new Mock<ILogger<CoursesController>>();

            _controller = new CoursesController(_context, envMock.Object, loggerMock.Object);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_webRootPath))
            {
                try { Directory.Delete(_webRootPath, true); } catch { }
            }
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.NotNull(model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsView()
        {
            var courseId = _context.Courses.First().CourseID;

            var result = _controller.Details(courseId) as ViewResult;

            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.Equal(courseId, course.CourseID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
            var model = result.Model as Course;
            Assert.NotNull(model);
        }

        [Fact]
        public void Create_POST_ValidCourse_RedirectsToIndex()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = deptId
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidCourse_AddsToDatabase()
        {
            var initialCount = _context.Courses.Count();
            var deptId = _context.Departments.First().DepartmentID;
            var course = new Course
            {
                CourseID = 8888,
                Title = "Another Course",
                Credits = 4,
                DepartmentID = deptId
            };

            _controller.Create(course, null);

            Assert.Equal(initialCount + 1, _context.Courses.Count());
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_WithValidImage_UploadsFile()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var course = new Course
            {
                CourseID = 7777,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = deptId
            };

            var content = new byte[] { 0xFF, 0xD8, 0xFF }; // JPEG header
            var file = new FormFile(new MemoryStream(content), 0, content.Length, "teachingMaterialImage", "test.jpg")
            {
                Headers = new HeaderDictionary(),
                ContentType = "image/jpeg"
            };

            _controller.Create(course, file);

            Assert.NotNull(course.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_WithInvalidExtension_ReturnsViewWithError()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var course = new Course
            {
                CourseID = 6666,
                Title = "Bad Image Course",
                Credits = 3,
                DepartmentID = deptId
            };

            var content = Encoding.UTF8.GetBytes("not an image");
            var file = new FormFile(new MemoryStream(content), 0, content.Length, "teachingMaterialImage", "test.txt")
            {
                Headers = new HeaderDictionary(),
                ContentType = "text/plain"
            };

            var result = _controller.Create(course, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_WithOversizedImage_ReturnsViewWithError()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var course = new Course
            {
                CourseID = 5555,
                Title = "Big Image Course",
                Credits = 3,
                DepartmentID = deptId
            };

            var content = new byte[6 * 1024 * 1024]; // 6MB
            var file = new FormFile(new MemoryStream(content), 0, content.Length, "teachingMaterialImage", "big.jpg")
            {
                Headers = new HeaderDictionary(),
                ContentType = "image/jpeg"
            };

            var result = _controller.Create(course, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsView()
        {
            var courseId = _context.Courses.First().CourseID;

            var result = _controller.Edit(courseId) as ViewResult;

            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.Equal(courseId, course.CourseID);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_ValidCourse_RedirectsToIndex()
        {
            var existing = _context.Courses.First();
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = existing.CourseID,
                Title = "Updated Title",
                Credits = existing.Credits,
                DepartmentID = existing.DepartmentID
            };

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_WithValidImage_UploadsNewFile()
        {
            var existing = _context.Courses.First();
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = existing.CourseID,
                Title = existing.Title,
                Credits = existing.Credits,
                DepartmentID = existing.DepartmentID
            };

            var content = new byte[] { 0xFF, 0xD8, 0xFF };
            var file = new FormFile(new MemoryStream(content), 0, content.Length, "teachingMaterialImage", "new.png")
            {
                Headers = new HeaderDictionary(),
                ContentType = "image/png"
            };

            _controller.Edit(course, file);

            Assert.NotNull(course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Edit_POST_InvalidImageExtension_ReturnsViewWithError()
        {
            var existing = _context.Courses.First();
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = existing.CourseID,
                Title = existing.Title,
                Credits = existing.Credits,
                DepartmentID = existing.DepartmentID
            };

            var content = Encoding.UTF8.GetBytes("not an image");
            var file = new FormFile(new MemoryStream(content), 0, content.Length, "teachingMaterialImage", "test.exe")
            {
                Headers = new HeaderDictionary(),
                ContentType = "application/octet-stream"
            };

            var result = _controller.Edit(course, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsView()
        {
            var courseId = _context.Courses.First().CourseID;

            var result = _controller.Delete(courseId) as ViewResult;

            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.Equal(courseId, course.CourseID);
        }

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_RemovesAndRedirects()
        {
            var courseId = _context.Courses.First().CourseID;
            var initialCount = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(courseId) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(initialCount - 1, _context.Courses.Count());
        }

        [Fact]
        public void DeleteConfirmed_WithImage_DeletesImageFile()
        {
            // Create a course with an image file
            var uploadsPath = Path.Combine(_webRootPath, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var imagePath = Path.Combine(uploadsPath, "test_image.jpg");
            File.WriteAllBytes(imagePath, new byte[] { 0xFF, 0xD8 });

            var deptId = _context.Departments.First().DepartmentID;
            var course = new Course
            {
                CourseID = 4444,
                Title = "Course With Image",
                Credits = 3,
                DepartmentID = deptId,
                TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg"
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            _controller.DeleteConfirmed(4444);

            Assert.False(File.Exists(imagePath));
        }
    }
}

