using ContosoUniversity.Models.SchoolViewModels;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ViewModelTests
    {
        [Fact]
        public void AssignedCourseData_Properties_CanBeSet()
        {
            var data = new AssignedCourseData
            {
                CourseID = 100,
                Title = "Chemistry",
                Assigned = true
            };
            Assert.Equal(100, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void AssignedCourseData_Assigned_DefaultsFalse()
        {
            var data = new AssignedCourseData();
            Assert.False(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_CanBeSet()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = new System.DateTime(2023, 9, 1),
                StudentCount = 25
            };
            Assert.Equal(new System.DateTime(2023, 9, 1), group.EnrollmentDate);
            Assert.Equal(25, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_IsNullable()
        {
            var group = new EnrollmentDateGroup { EnrollmentDate = null };
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_Properties_CanBeSet()
        {
            var data = new InstructorIndexData
            {
                Instructors = new[] { new ContosoUniversity.Models.Instructor { FirstMidName = "A", LastName = "B" } },
                Courses = new[] { new ContosoUniversity.Models.Course { CourseID = 1, Title = "C" } },
                Enrollments = new[] { new ContosoUniversity.Models.Enrollment { EnrollmentID = 1 } }
            };
            Assert.Single(data.Instructors);
            Assert.Single(data.Courses);
            Assert.Single(data.Enrollments);
        }

        [Fact]
        public void InstructorIndexData_Collections_DefaultToNull()
        {
            var data = new InstructorIndexData();
            Assert.Null(data.Instructors);
            Assert.Null(data.Courses);
            Assert.Null(data.Enrollments);
        }
    }
}

